using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Storage.ValueConversion;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents are found and raw SQL queries still work.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: id no longer synthesized as "EntityType|Key".
            // Use a value converter to preserve the old "Blog|{key}" format.
            entity.Property(b => b.Id).HasConversion(
                new ValueConverter<string, string>(
                    v => "Blog|" + v,
                    v => v.StartsWith("Blog|") ? v.Substring("Blog|".Length) : v));

            // Breaking change 3: HasIndex throws for Cosmos provider (was silently ignored).
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

